import{_ as a,o as n,c as l,a2 as e}from"./chunks/framework.DH0WjybD.js";const u=JSON.parse('{"title":"Tailwind CSS","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/tailwind-css.md","filePath":"knowledge/tailwind-css.md","lastUpdated":null}'),o={name:"knowledge/tailwind-css.md"};function p(r,s,i,c,t,d){return n(),l("div",null,[...s[0]||(s[0]=[e(`<h1 id="tailwind-css" tabindex="-1">Tailwind CSS <a class="header-anchor" href="#tailwind-css" aria-label="Permalink to &quot;Tailwind CSS&quot;">​</a></h1><h2 id="知识简介" tabindex="-1">知识简介 <a class="header-anchor" href="#知识简介" aria-label="Permalink to &quot;知识简介&quot;">​</a></h2><p>Tailwind CSS 是一个以原子化 CSS 类为核心的 CSS 框架，通过在 HTML 中直接使用预定义的 class（如 <code>flex</code>、<code>bg-blue-500</code>、<code>p-4</code>）来构建界面，无需编写自定义 CSS。jinzhuan-project-web 项目同时使用 Tailwind CSS 和 Windi CSS。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li><strong>原子化类</strong>：每个类只做一件事（如 <code>text-center</code> 只设置文本居中）</li><li><strong>响应式前缀</strong>：<code>sm:</code>、<code>md:</code>、<code>lg:</code>、<code>xl:</code>（如 <code>md:flex</code>）</li><li><strong>暗黑模式</strong>：<code>dark:</code> 前缀</li><li><strong>CSS 变量</strong>：通过 CSS 自定义属性实现主题系统</li><li><strong>工具组合</strong>：组合多个类来构建复杂样式</li></ul><h2 id="详细讲解" tabindex="-1">详细讲解 <a class="header-anchor" href="#详细讲解" aria-label="Permalink to &quot;详细讲解&quot;">​</a></h2><p>在 jinzhuan-project-web 项目中，Tailwind CSS 配合 <code>tailwindcss-animate</code> 插件实现动画，配置文件（<code>tailwind.config.js</code>）中定义了基于 CSS 变量的设计系统：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">colors</span><span style="color:#E1E4E8;">: {</span></span>
<span class="line"><span style="color:#B392F0;">  border</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;hsl(var(--border))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#B392F0;">  background</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;hsl(var(--background))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#B392F0;">  primary</span><span style="color:#E1E4E8;">: {</span></span>
<span class="line"><span style="color:#B392F0;">    DEFAULT</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;hsl(var(--primary))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#B392F0;">    foreground</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;hsl(var(--primary-foreground))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  }</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这种设计方式常用于 shadcn-vue 组件系统，使得主题可以灵活切换（通过修改 CSS 变量）。</p><p>Tailwind CSS 的核心优势：</p><ul><li>不需要离开 HTML 编写样式</li><li>打包时自动移除未使用的 CSS（PurgeCSS）</li><li>内置响应式设计和暗黑模式支持</li><li>通过配置文件实现设计系统</li></ul><h2 id="重点内容" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容" aria-label="Permalink to &quot;重点内容&quot;">​</a></h2><ul><li>布局类：<code>flex</code>、<code>grid</code>、<code>block</code>、<code>hidden</code></li><li>间距类：<code>p-4</code>（padding）、<code>m-2</code>（margin）、<code>gap-4</code></li><li>颜色类：<code>bg-blue-500</code>、<code>text-white</code>、<code>border-gray-200</code></li><li>尺寸类：<code>w-full</code>、<code>h-screen</code>、<code>max-w-md</code></li><li>排版类：<code>text-lg</code>、<code>font-bold</code>、<code>text-center</code></li></ul><h2 id="关键代码示例" tabindex="-1">关键代码示例 <a class="header-anchor" href="#关键代码示例" aria-label="Permalink to &quot;关键代码示例&quot;">​</a></h2><p>来源：<code>jinzhuan-project-web/tailwind.config.js</code></p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">export</span><span style="color:#F97583;"> default</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#E1E4E8;">  darkMode: </span><span style="color:#9ECBFF;">&quot;selector&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  safelist: [</span><span style="color:#9ECBFF;">&quot;dark&quot;</span><span style="color:#E1E4E8;">],</span></span>
<span class="line"><span style="color:#E1E4E8;">  prefix: </span><span style="color:#9ECBFF;">&quot;&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  content: [</span><span style="color:#9ECBFF;">&quot;./index.html&quot;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&quot;./src/**/*.{vue,js,ts,jsx,tsx}&quot;</span><span style="color:#E1E4E8;">],</span></span>
<span class="line"><span style="color:#E1E4E8;">  theme: {</span></span>
<span class="line"><span style="color:#E1E4E8;">    extend: {</span></span>
<span class="line"><span style="color:#E1E4E8;">      colors: {</span></span>
<span class="line"><span style="color:#E1E4E8;">        border: </span><span style="color:#9ECBFF;">&quot;hsl(var(--border))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        input: </span><span style="color:#9ECBFF;">&quot;hsl(var(--input))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        background: </span><span style="color:#9ECBFF;">&quot;hsl(var(--background))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        foreground: </span><span style="color:#9ECBFF;">&quot;hsl(var(--foreground))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        primary: {</span></span>
<span class="line"><span style="color:#E1E4E8;">          DEFAULT: </span><span style="color:#9ECBFF;">&quot;hsl(var(--primary))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">          foreground: </span><span style="color:#9ECBFF;">&quot;hsl(var(--primary-foreground))&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        }</span></span>
<span class="line"><span style="color:#E1E4E8;">      },</span></span>
<span class="line"><span style="color:#E1E4E8;">      borderRadius: {</span></span>
<span class="line"><span style="color:#E1E4E8;">        lg: </span><span style="color:#9ECBFF;">&quot;var(--radius)&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        md: </span><span style="color:#9ECBFF;">&quot;calc(var(--radius) - 2px)&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        sm: </span><span style="color:#9ECBFF;">&quot;calc(var(--radius) - 4px)&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">      }</span></span>
<span class="line"><span style="color:#E1E4E8;">    }</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">  plugins: [animate, setupInspiraUI]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h2 id="实际应用场景" tabindex="-1">实际应用场景 <a class="header-anchor" href="#实际应用场景" aria-label="Permalink to &quot;实际应用场景&quot;">​</a></h2><ul><li>快速原型开发</li><li>组件库设计系统（如 shadcn-vue）</li><li>响应式布局</li><li>暗黑模式切换</li><li>到UI组件的高效转换</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>HTML 中 class 可能很长，可以使用 <code>@apply</code> 指令提取重复样式</li><li>生产构建会移除未使用的样式，确保 <code>content</code> 路径配置正确</li><li>Tailwind CSS 3.x 使用 Just-in-Time (JIT) 引擎，按需生成样式</li><li>自定义颜色需要通过配置文件或 CSS 变量</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>误区：Tailwind CSS 是内联样式（实际上是 class 形式）</li><li>误区：认为使用 Tailwind 就不用写 CSS（复杂场景仍需自定义）</li><li>误区：所有样式都写在 class 中（复杂样式应该提取为组件）</li></ul><h2 id="关联知识点" tabindex="-1">关联知识点 <a class="header-anchor" href="#关联知识点" aria-label="Permalink to &quot;关联知识点&quot;">​</a></h2><ul><li><a href="/frontend-knowledge-base/knowledge/sass-scss.html">Sass/SCSS</a></li><li><a href="/frontend-knowledge-base/knowledge/ant-design-vue3.html">Ant Design Vue 3</a></li><li><a href="/frontend-knowledge-base/knowledge/vite-plugins.html">Vite 插件系统</a></li></ul><h2 id="资料来源" tabindex="-1">资料来源 <a class="header-anchor" href="#资料来源" aria-label="Permalink to &quot;资料来源&quot;">​</a></h2><ul><li>来源项目：<code>新前端资源/jinzhuan-project-web/</code></li><li>来源文件：<code>tailwind.config.js</code>（完整配置）</li><li>来源文件：<code>windi.config.ts</code>（Windi CSS 配置）</li><li>来源文件：<code>src/assets/css/web3-theme.scss</code>（CSS 变量主题）</li></ul><h2 id="官方资源扩展" tabindex="-1">官方资源扩展 <a class="header-anchor" href="#官方资源扩展" aria-label="Permalink to &quot;官方资源扩展&quot;">​</a></h2><ul><li><a href="https://tailwindcss.com/docs" target="_blank" rel="noreferrer">Tailwind CSS 官方文档</a></li><li>Tailwind CSS 官方文档，包含所有原子化类的完整参考</li><li><a href="https://windicss.org/" target="_blank" rel="noreferrer">Windi CSS 官方文档</a></li><li>Windi CSS 官方文档（与 Tailwind 兼容的替代方案）</li></ul>`,28)])])}const b=a(o,[["render",p]]);export{u as __pageData,b as default};
